// Narrative interpretations for the CSAI-2 (Competitive State Anxiety Inventory-2).
// 3 subscales x 3 bands x 3 languages (en, hu, de).
// Tone: direct, practical sport-psychology voice for competitive strength/combat athletes.
// Important: CSAI-2 is a STATE measure -- results reflect how the athlete feels
// right now, before this specific competition, not a permanent trait.

import type { CsaiSubscaleKey, Band } from "./scoring";

// ---------------------------------------------------------------------------
// Shared types
// ---------------------------------------------------------------------------

export type LocalizedParagraphs = { en: string[]; hu: string[]; de: string[] };

export type SubscaleInterpretation = {
  name: { en: string; hu: string; de: string };
  definition: { en: string; hu: string; de: string };
  bands: Record<Band, LocalizedParagraphs>;
};

// ---------------------------------------------------------------------------
// General intro
// ---------------------------------------------------------------------------

